35			{AnchorStart: `<s>`, AnchorEnd: `</s>`, Start: "\x1b[9m", End: "\x1b[29m"},
36			{AnchorStart: `<d>`, AnchorEnd: `</d>`, Start: "\x1b[2m", End: "\x1b[22m"},
37			{AnchorStart: `<f>`, AnchorEnd: `</f>`, Start: "\x1b[5m", End: "\x1b[25m"},
38			{AnchorStart: `<r>`, AnchorEnd: `</r>`, Start: "\x1b[7m", End: "\x1b[27m"},
39		}
40	
41		resetStyle      = &style{AnchorStart: "RESET", AnchorEnd: `</>`, End: "\x1b[0m"}
42		backgroundStyle = &style{AnchorStart: "BACKGROUND", AnchorEnd: `</>`, End: "\x1b[49m"}
43	
44		BackgroundColor color.Ansi
45		CurrentColors   *color.Set
46		ParentColors    []*color.Set
47		Colors          color.String
48	
49		Plain       bool
50		Interactive bool
51	
52		builder strings.Builder
53		length  int
54	
55		foregroundColor color.Ansi
56		backgroundColor color.Ansi
57		currentColor    color.History
58		textLen         int
59	
60		isTransparent bool
61		isInvisible   bool
62		isHyperlink   bool
63	
64		Shell   string
65		Program string
66	
67		progressTerminals []string
68	
69		formats *shell.Formats
70	
71		// escapePrefix/escapeSuffix are formats.Escape ("...%s...") split around its
72		// single %s placeholder, precomputed once so writeEscapedAnsiString can
73		// concatenate via the builder instead of allocating through fmt.Sprintf.
74		escapePrefix string
75		escapeSuffix string
76	)
77	
78	const (
79		AnchorRegex = `^(?P<ANCHOR><(?P<FG>[^,<>]+)?,?(?P<BG>[^<>]+)?>)`
80	
81		// colorisePrefix/coloriseSuffix and transparentStartPrefix/transparentStartSuffix
82		// are the fixed parts of the colorise ("\x1b[%sm") and transparentStart
83		// ("\x1b[0m\x1b[%s;49m\x1b[7m") formats, split around their single %s
84		// placeholder so callers can write them directly via the builder instead
85		// of allocating through fmt.Sprintf.
86		colorisePrefix = "\x1b["
87		coloriseSuffix = "m"
88	
89		transparentStartPrefix = "\x1b[0m\x1b["
90		transparentStartSuffix = ";49m\x1b[7m"
91	
92		transparentEnd = "\x1b[27m"
93		backgroundEnd  = "\x1b[49m"
94	
95		AnsiRegex = "[\u001B\u009B][[\\]()#;?]*(?:(?:(?:[a-zA-Z\\d]*(?:;[a-zA-Z\\d]*)*)?\u0007)|(?:(?:\\d{1,4}(?:;\\d{0,4})*)?[\\dA-PRZcf-ntqry=><~]))"
96	
97		OSC99 = "osc99"
98		OSC7  = "osc7"
99		OSC51 = "osc51"
100	
101		ANCHOR = "ANCHOR"
102		BG     = "BG"
103		FG     = "FG"
104	
105		hyperLinkStart   = "<LINK>"
106		hyperLinkEnd     = "</LINK>"
107		hyperLinkText    = "<TEXT>"
108		hyperLinkTextEnd = "</TEXT>"
109	
110		empty = "<>"
111	
112		startProgress = "\x1b]9;4;3;0\x07"
113		setProgress   = "\x1b]9;4;4;%d\x07"
114		endProgress   = "\x1b]9;4;0;0\x07"
115	
116		WindowsTerminal = "Windows Terminal"
117		Warp            = "WarpTerminal"
118		ITerm           = "iTerm.app"
119		AppleTerminal   = "Apple_Terminal"
120		Unknown         = "Unknown"
121	)
122	
123	// anchorMatch describes a single `<...>` anchor token found while scanning
124	// segment text, mirroring the named groups of AnchorRegex without allocating
125	// a map or invoking the regexp engine.
126	type anchorMatch struct {
127		Anchor string
128		FG     string
129		BG     string
130		ok     bool
131	}
132	
133	// scanAnchor looks for an AnchorRegex-shaped token at the start of txt, i.e.
134	// `<` + zero or more non `<>` characters + `>`, with the inner text optionally
135	// split on the first comma into FG (before) and BG (after, which may itself
136	// contain further commas). It operates on the zero-copy slice txt[i:] and
137	// performs no allocations.
138	func scanAnchor(txt string) anchorMatch {
139		if len(txt) == 0 || txt[0] != '<' {
140			return anchorMatch{}
141		}
142	
143		end := strings.IndexByte(txt, '>')
144		if end < 0 {
145			return anchorMatch{}
146		}
147	
148		inner := txt[1:end]
149		if strings.IndexByte(inner, '<') >= 0 {
150			return anchorMatch{}
151		}
152	
153		fg := inner
154		bg := ""
155	
156		if before, after, ok := strings.Cut(inner, ","); ok {
157			fg = before
158			bg = after
159		}
160	
161		return anchorMatch{
162			Anchor: txt[:end+1],
163			FG:     fg,
164			BG:     bg,
165			ok:     true,
166		}
167	}
168	
169	func Init(sh string) {
170		Shell = sh
171		Program = getTerminalName()
172	
173		log.Debug("terminal program:", Program)
174		log.Debug("terminal shell:", Shell)
175	
176		color.TrueColor = Program != AppleTerminal
177	
178		progressTerminals = []string{WindowsTerminal}
179		formats = shell.GetFormats(Shell)
180	
181		escapePrefix, escapeSuffix = "", ""
182		if before, after, found := strings.Cut(formats.Escape, "%s"); found {
183			// formats.Escape is a fmt.Sprintf format string, so any literal "%"
184			// in the surrounding text is escaped as "%%" (e.g. zsh's "%%{%s%%}").
185			// Unescape it now since we no longer route through fmt.Sprintf.
186			escapePrefix = strings.ReplaceAll(before, "%%", "%")
187			escapeSuffix = strings.ReplaceAll(after, "%%", "%")
188		}
189	}
190	
191	func getTerminalName() string {
192		Program = os.Getenv("TERM_PROGRAM")
193		if len(Program) != 0 {
194			return Program
195		}
196	
197		wtSession := os.Getenv("WT_SESSION")
198		if len(wtSession) != 0 {
199			return WindowsTerminal
200		}
201	
202		return Unknown
203	}
204	
205	func SetColors(background, foreground color.Ansi) {
206		CurrentColors = &color.Set{
207			Background: background,
208			Foreground: foreground,
209		}
210	}
211	
212	func SetParentColors(background, foreground color.Ansi) {
213		if ParentColors == nil {
214			ParentColors = make([]*color.Set, 0)
215		}
216	
217		ParentColors = append([]*color.Set{{
218			Background: background,
219			Foreground: foreground,
220		}}, ParentColors...)
221	}
222	
223	func ChangeLine(numberOfLines int) string {
224		if Plain {
225			return ""
226		}
227	
228		position := "B"
229	
230		if numberOfLines < 0 {
231			position = "F"
232			numberOfLines = -numberOfLines
233		}
234	
235		return fmt.Sprintf(formats.Linechange, numberOfLines, position)
236	}
237	
238	func Pwd(pwdType, userName, hostName, pwd string) string {
239		if Plain {
240			return ""
241		}
242	
243		switch pwdType {
244		case OSC7:
245			return fmt.Sprintf(formats.Osc7, hostName, pwd)
246		case OSC51:
247			return fmt.Sprintf(formats.Osc51, userName, hostName, pwd)
248		case OSC99:
249			fallthrough
250		default:
251			return fmt.Sprintf(formats.Osc99, pwd)
252		}
253	}
254	
255	func ClearAfter() string {
256		if Plain {
257			return ""
258		}
259	
260		return formats.ClearLine + formats.ClearBelow
261	}
262	
263	func FormatTitle(title string) string {
264		switch Shell {
265		// These shells don't support setting the console title.
266		case shell.ELVISH, shell.XONSH:
267			return ""
268		case shell.BASH, shell.ZSH, shell.YASH:
269			title = trimAnsi(title)
270	
271			sb := text.NewBuilder()
272	
273			// We have to do this to prevent the shell from misidentifying escape sequences.
274			for _, char := range title {
275				escaped, shouldEscape := formats.EscapeSequences[char]
276				if shouldEscape {
277					sb.WriteString(escaped)
278					continue
279				}
280	
281				sb.WriteRune(char)
282			}
283	
284			return fmt.Sprintf(formats.Title, sb.String())
285		default:
286			return fmt.Sprintf(formats.Title, trimAnsi(title))
287		}
288	}
289	
290	func EscapeText(txt string) string {
291		return fmt.Sprintf(formats.Escape, txt)
292	}
293	
294	func SaveCursorPosition() string {
295		return formats.SaveCursorPosition
296	}
297	
298	func RestoreCursorPosition() string {
299		return formats.RestoreCursorPosition
300	}
301	
302	func PromptStart() string {
303		return fmt.Sprintf(formats.Escape, "\x1b]133;A\007")
304	}
305	
306	func CommandStart() string {
307		return fmt.Sprintf(formats.Escape, "\x1b]133;B\007")
308	}
309	
310	func CommandFinished(code int, ignore bool) string {
311		if ignore {
312			return fmt.Sprintf(formats.Escape, "\x1b]133;D\007")
313		}
314	
315		mark := fmt.Sprintf("\x1b]133;D;%d\007", code)
316	
317		return fmt.Sprintf(formats.Escape, mark)
318	}
319	
320	func LineBreak() string {
321		cr := fmt.Sprintf(formats.Left, 1000)
322		lf := fmt.Sprintf(formats.Linechange, 1, "B")
323		return cr + lf
324	}
325	
326	func progressSupported() bool {
327		return slices.ContainsFunc(progressTerminals, func(program string) bool {
328			return strings.EqualFold(program, Program)
329		})
330	}
331	
332	func StartProgress() string {
333		if !progressSupported() {
334			return ""
335		}
336	
337		return startProgress
338	}
339	
340	func SetProgress(percentage int) string {
341		if !progressSupported() {
342			return ""
343		}
344	
345		return fmt.Sprintf(setProgress, percentage)
346	}
347	
348	func StopProgress() string {
349		if !progressSupported() {
350			return ""
351		}
352	
353		return endProgress
354	}
355	
356	func Write(background, foreground color.Ansi, txt string) {
357		if txt == "" {
358			return
359		}
360	
361		backgroundColor, foregroundColor = asAnsiColors(background, foreground)
362	
363		// default to white foreground
364		if foregroundColor.IsEmpty() {
365			foregroundColor = Colors.ToAnsi("white", false)
366		}
367	
368		// validate if we start with a color override
369		match := scanAnchor(txt)
370		if match.ok && match.Anchor != hyperLinkStart {
371			colorOverride := true
372			for _, style := range knownStyles {
373				if match.Anchor != style.AnchorStart {
374					continue
375				}
376	
377				writeEscapedAnsiString(style.Start)
378				colorOverride = false
379			}
380	
381			if colorOverride {
382				currentColor.Add(asAnsiColors(color.Ansi(match.BG), color.Ansi(match.FG)))
383			}
384		}
385	
386		writeSegmentColors()
387	
388		// print the hyperlink part AFTER the coloring
389		if match.ok && match.Anchor == hyperLinkStart {
390			isHyperlink = true
391			builder.WriteString(formats.HyperlinkStart)
392		}
393	
394		txt = txt[len(match.Anchor):]
395		textLen = len(txt)
396		hyperlinkTextPosition := 0
397	
398		for i := 0; i < len(txt); {
399			s, size := utf8.DecodeRuneInString(txt[i:])
400	
401			// ignore everything which isn't overriding
402			if s != '<' {
403				write(s)
404				i += size
405				continue
406			}
407	
408			// color/end overrides first
409			match = scanAnchor(txt[i:])
410			if match.ok {
411				// check for hyperlinks first
412				switch match.Anchor {
413				case hyperLinkStart:
414					isHyperlink = true
415					i += len(match.Anchor)
416					builder.WriteString(formats.HyperlinkStart)
417					continue
418				case hyperLinkText:
419					isHyperlink = false
420					i += len(match.Anchor)
421					hyperlinkTextPosition = i
422					builder.WriteString(formats.HyperlinkCenter)
423					continue
424				case hyperLinkTextEnd:
425					// this implies there's no text in the hyperlink
426					if hyperlinkTextPosition == i {
427						builder.WriteString("link")
428						length += 4
429					}
430					i += len(match.Anchor)
431					continue
432				case hyperLinkEnd:
433					i += len(match.Anchor)
434					builder.WriteString(formats.HyperlinkEnd)
435					continue
436				case empty:
437					i += len(match.Anchor)
438					continue
439				}
440	
441				i = writeAnchorOverride(match, background, i)
442				continue
443			}
444	
445			write(s)
446			i += size
447		}
448	
449		// reset colors
450		writeEscapedAnsiString(resetStyle.End)
451	
452		// pop last color from the stack
453		currentColor.Pop()
454	}
455	
456	func Len() int {
457		return length
458	}
459	
460	func String() (string, int) {
461		defer func() {
462			length = 0
463			builder.Reset()
464	
465			isTransparent = false
466			isInvisible = false
467		}()
468	
469		return builder.String(), length
470	}
471	
472	func writeEscapedAnsiString(txt string) {
473		if Plain {
474			return
475		}
476	
477		if len(escapePrefix) != 0 {
478			builder.WriteString(escapePrefix)
479		}
480	
481		builder.WriteString(txt)
482	
483		if len(escapeSuffix) != 0 {
484			builder.WriteString(escapeSuffix)
485		}
486	}
487	
488	// writeEscapedAnsiParts writes prefix+payload+suffix wrapped in the shell escape
489	// sequence, avoiding the intermediate string concatenation that a
490	// fmt.Sprintf(colorise/transparentStart, ...) call would otherwise require.
491	func writeEscapedAnsiParts(prefix string, payload color.Ansi, suffix string) {
492		if Plain {
493			return
494		}
495	
496		if len(escapePrefix) != 0 {
497			builder.WriteString(escapePrefix)
498		}
499	
500		builder.WriteString(prefix)
501		builder.WriteString(payload.String())
502		builder.WriteString(suffix)
503	
504		if len(escapeSuffix) != 0 {
505			builder.WriteString(escapeSuffix)
506		}
507	}
508	
509	// writeColorise writes the equivalent of fmt.Sprintf(colorise, c) wrapped in
510	// the shell escape sequence, without allocating an intermediate string.
511	func writeColorise(c color.Ansi) {
512		writeEscapedAnsiParts(colorisePrefix, c, coloriseSuffix)
513	}
514	
515	// writeTransparentStart writes the equivalent of fmt.Sprintf(transparentStart, c)
516	// wrapped in the shell escape sequence, without allocating an intermediate string.
517	func writeTransparentStart(c color.Ansi) {
518		writeEscapedAnsiParts(transparentStartPrefix, c, transparentStartSuffix)
519	}
520	
521	func write(s rune) {
522		if isInvisible {
523			return
524		}
525	
526		if isHyperlink {
527			builder.WriteRune(s)
528			return
529		}
530	
531		// UNSOLVABLE: When "Interactive" is true, the prompt length calculation in Bash/Zsh can be wrong, since the final string expansion is done by shells.
532		length += runewidth.RuneWidth(s)
533		// length += utf8.RuneCountInString(string(s))
534	
535		if !Interactive && !Plain {
536			escaped, shouldEscape := formats.EscapeSequences[s]
537			if shouldEscape {
538				builder.WriteString(escaped)
539				return
540			}
541		}
542	
543		builder.WriteRune(s)
544	}
545	
546	func writeSegmentColors() {
547		// use correct starting colors
548		bg := backgroundColor
549		fg := foregroundColor
550		if !currentColor.Background().IsEmpty() {
551			bg = currentColor.Background()
552		}
553		if !currentColor.Foreground().IsEmpty() {
554			fg = currentColor.Foreground()
555		}
556	
557		// ignore processing fully transparent colors
558		isInvisible = fg.IsTransparent() && bg.IsTransparent()
559		if isInvisible {
560			return
561		}
562	
563		switch {
564		case fg.IsTransparent() && len(BackgroundColor) != 0:
565			background := Colors.ToAnsi(BackgroundColor, false)
566			writeColorise(background)
567			writeColorise(bg.ToForeground())
568		case fg.IsTransparent() && !bg.IsEmpty():
569			isTransparent = true
570			writeTransparentStart(bg)
571		default:
572			if !bg.IsEmpty() && !bg.IsTransparent() {
573				writeColorise(bg)
574			}
575	
576			if !fg.IsEmpty() && !fg.IsTransparent() {
577				writeColorise(fg)
578			}
579		}
580	
581		// set current colors
582		currentColor.Add(bg, fg)
583	}
584	
585	func writeAnchorOverride(match anchorMatch, background color.Ansi, i int) int {
586		position := i
587		// check color reset first
588		if match.Anchor == resetStyle.AnchorEnd {
589			return endColorOverride(position)
590		}
591	
592		position += len(match.Anchor)
593	
594		for _, style := range knownStyles {
595			if style.AnchorEnd == match.Anchor {
596				writeEscapedAnsiString(style.End)
597				return position
598			}
599			if style.AnchorStart == match.Anchor {
600				writeEscapedAnsiString(style.Start)
601				return position
602			}
603		}
604	
605		bgColor := color.Ansi(match.BG)
606		fgColor := color.Ansi(match.FG)
607	
608		if fgColor.IsTransparent() && bgColor.IsEmpty() {
609			bgColor = background
610		}
611	
612		bg, fg := asAnsiColors(bgColor, fgColor)
613	
614		// ignore processing fully transparent colors
615		isInvisible = fg.IsTransparent() && bg.IsTransparent()
616		if isInvisible {
617			return position
618		}
619	
620		// make sure we have colors
621		if fg.IsEmpty() {
622			fg = foregroundColor
623		}
624		if bg.IsEmpty() {
625			bg = backgroundColor
626		}
627	
628		currentColor.Add(bg, fg)
629	
630		if currentColor.Foreground().IsTransparent() && len(BackgroundColor) != 0 {
631			background := Colors.ToAnsi(BackgroundColor, false)
632			writeColorise(background)
633			writeColorise(currentColor.Background().ToForeground())
634			return position
635		}
636	
637		if currentColor.Foreground().IsTransparent() && !currentColor.Background().IsTransparent() {
638			isTransparent = true
639			writeTransparentStart(currentColor.Background())
640			return position
641		}
642	
643		if currentColor.Background() != backgroundColor {
644			// end the colors in case we have a transparent background
645			if currentColor.Background().IsTransparent() {
646				writeEscapedAnsiString(backgroundEnd)
647			} else {
648				writeColorise(currentColor.Background())
649			}
650		}
651	
652		if currentColor.Foreground() != foregroundColor {
653			writeColorise(currentColor.Foreground())
654		}
655	
656		return position
657	}
658	
659	func endColorOverride(position int) int {
660		// make sure to reset the colors if needed
661		position += len(resetStyle.AnchorEnd)
662	
663		// do not restore colors at the end of the string, we print it anyways
664		if position == textLen {
665			currentColor.Pop()
666			return position
667		}
668	
669		// reset colors to previous when we have more than 1 in stack
670		// as soon as we have  more than 1, we can pop the last one
671		// and print the previous override as it wasn't ended yet
672		if currentColor.Len() > 1 {
673			fg := currentColor.Foreground()
674			bg := currentColor.Background()
675	
676			currentColor.Pop()
677	
678			previousBg := currentColor.Background()
679			previousFg := currentColor.Foreground()
680	
681			if isTransparent {
682				writeEscapedAnsiString(transparentEnd)
683			}
684	
685			if previousBg != bg {
686				if previousBg.IsClear() {
687					writeEscapedAnsiString(backgroundStyle.End)
688				} else {
689					writeColorise(previousBg)
690				}
691			}
692	
693			if previousFg != fg {
694				writeColorise(previousFg)
695			}
696	
697			return position
698		}
699	
700		// pop the last colors from the stack
701		defer currentColor.Pop()
702	
703		// do not reset when colors are identical
704		if currentColor.Background() == backgroundColor && currentColor.Foreground() == foregroundColor {
705			return position
706		}
707	
708		if isTransparent {
709			writeEscapedAnsiString(transparentEnd)
710		}
711	
712		if backgroundColor.IsClear() {
713			writeEscapedAnsiString(backgroundStyle.End)
714		}
715	
716		if currentColor.Background() != backgroundColor && !backgroundColor.IsClear() {
717			writeColorise(backgroundColor)
718		}
719	
720		if (currentColor.Foreground() != foregroundColor || isTransparent) && !foregroundColor.IsClear() {
721			writeColorise(foregroundColor)
722		}
723	
724		isTransparent = false
725		return position
726	}
727	
728	func asAnsiColors(background, foreground color.Ansi) (color.Ansi, color.Ansi) {
729		if background == "" {
730			background = color.Background
731		}
732	
733		if foreground == "" {
734			foreground = color.Foreground
735		}
736	
737		background = background.Resolve(CurrentColors, ParentColors)
738		foreground = foreground.Resolve(CurrentColors, ParentColors)
739	
740		if bg, err := Colors.Resolve(background); err == nil {
741			background = bg
742		}
743	
744		if fg, err := Colors.Resolve(foreground); err == nil {
745			foreground = fg
746		}
747	
748		inverted := foreground == color.Transparent && len(background) != 0
749	
750		background = Colors.ToAnsi(background, !inverted)
751		foreground = Colors.ToAnsi(foreground, false)
752	
753		return background, foreground
754	}
755	
756	func trimAnsi(txt string) string {
757		if txt == "" || !strings.Contains(txt, "\x1b") {
758			return txt
759		}
760		return regex.ReplaceAllString(AnsiRegex, txt, "")
761	}
