// a gradient, or when the gradient syntax is invalid.
func (c Ansi) GradientLast() Ansi {
	stops := c.GradientStops()
	if len(stops) == 0 {
		return c
	}

	return stops[len(stops)-1]
}

// GradientCells resolves each stop of the gradient c through resolver (palette references,
// etc.), parses the result as a hex color, and interpolates across cells steps in HCL space.
// It returns one ready-to-print ANSI color code per cell, honoring the package-level TrueColor
// flag: a truecolor escape when true, a gookit C256 downgrade when false. cells == 1 returns
// only the first stop. Returns nil when fewer than two stops resolve to a valid color; the
// caller falls back to a single collapsed color per the gradient-invalid rule.
func GradientCells(c Ansi, cells int, resolver String, isBackground bool) []Ansi {
	if cells <= 0 {
		return nil
	}

	stops := c.GradientStops()
	if len(stops) == 0 {
		return nil
	}

	colors := make([]colorful.Color, 0, len(stops))

	for _, stop := range stops {
		resolved, err := resolver.Resolve(stop)
		if err != nil {
			log.Errorf("gradient %s: unable to resolve stop %s: %s", c, stop, err)
			continue
		}

		clr, err := colorful.Hex(resolved.String())
		if err != nil {
			log.Errorf("gradient %s: stop %s does not resolve to a hex color, only hex colors and palette references to hex colors can be interpolated", c, stop)
			continue
		}

		colors = append(colors, clr)
	}

	if len(colors) < 2 {
		log.Errorf("gradient %s: needs at least two valid stops, rendering the first stop as a solid color", c)
		return nil
	}

	if cells == 1 {
		return []Ansi{ansiFromColorful(colors[0], isBackground)}
	}

	segments := len(colors) - 1
	result := make([]Ansi, cells)

	for i := range cells {
		position := float64(i) / float64(cells-1) * float64(segments)

		segment := int(position)
		if segment >= segments {
			segment = segments - 1
		}

		blended := colors[segment].BlendHcl(colors[segment+1], position-float64(segment)).Clamped()
		result[i] = ansiFromColorful(blended, isBackground)
	}

	return result
}

// ansiFromColorful converts an interpolated HCL color to a ready-to-print ANSI code, honoring
// the package-level TrueColor flag.
func ansiFromColorful(c colorful.Color, isBackground bool) Ansi {
	r, g, b := c.RGB255()

	rgb := color.RGB(r, g, b, isBackground)
	if TrueColor {
		return Ansi(rgb.String())
	}

	return Ansi(rgb.C256().String())
}

